		if err := initStore(); err != nil {
			klog.Fatalf("init store failed: %v", err)
		}
	})
	return provider
}

func initStore() error {
	storeType := strings.ToLower(os.Getenv("STORE_TYPE"))
	if storeType == "" {
		storeType = redisStoreType
	}

	var err error
	switch storeType {
	case redisStoreType:
		provider, err = newRedisStore()
		if err != nil {
			return fmt.Errorf("failed to create redis store: %w", err)
		}
	case valkeyStoreType:
		provider, err = newValkeyStore()
		if err != nil {
			return fmt.Errorf("failed to create valkey store: %w", err)
		}
	default:
		return fmt.Errorf("unsupported store type: %s", storeType)
	}

	return nil
}

func sessionKey(prefix, sessionID string) string {
	return prefix + sessionID
}

func loadSandboxesBySessionIDs(ctx context.Context, s Store, sessionIDs []string, sessionPrefix string, getter func(string) ([]byte, error)) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return []*types.SandboxInfo{}, nil
	}

	var sandboxes []*types.SandboxInfo
	for _, sid := range sessionIDs {
		data, err := getter(sessionKey(sessionPrefix, sid))
		if err != nil {
			if err == ErrNotFound {
				continue
			}
			return nil, err
		}

		sandbox := &types.SandboxInfo{}
		if err := json.Unmarshal(data, sandbox); err != nil {
			return nil, fmt.Errorf("failed to unmarshal sandbox data: %w", err)
		}
		sandboxes = append(sandboxes, sandbox)
	}

	return sandboxes, nil
}

func parseBoolEnv(envVar string, defaultValue bool) bool {
	val := os.Getenv(envVar)
	if val == "" {
		return defaultValue
	}
	parsed, err := strconv.ParseBool(val)
	if err != nil {
		return defaultValue
	}
	return parsed
}

