		return []*types.SandboxInfo{}, nil
	}

	var sandboxes []*types.SandboxInfo
	for _, sid := range sessionIDs {
		data, err := getter(sessionKey(sessionPrefix, sid))
		if err != nil {
			if err == ErrNotFound {
				continue
			}
			return nil, err
		}

		sandbox := &types.SandboxInfo{}
		if err := json.Unmarshal(data, sandbox); err != nil {
			return nil, fmt.Errorf("failed to unmarshal sandbox data: %w", err)
		}
		sandboxes = append(sandboxes, sandbox)
	}

	return sandboxes, nil
}

func parseBoolEnv(envVar string, defaultValue bool) bool {
	val := os.Getenv(envVar)
	if val == "" {
		return defaultValue
	}
	parsed, err := strconv.ParseBool(val)
	if err != nil {
		return defaultValue
	}
	return parsed
}

